import{_ as t,o,c as a,ag as r}from"./chunks/framework.BYYsWsaA.js";const m=JSON.parse('{"title":"Import & Export","description":"","frontmatter":{},"headers":[],"relativePath":"guide/import-export.md","filePath":"guide/import-export.md"}'),i={name:"guide/import-export.md"};function s(n,e,d,l,c,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="import-export" tabindex="-1">Import &amp; Export <a class="header-anchor" href="#import-export" aria-label="Permalink to &quot;Import &amp; Export&quot;">​</a></h1><p>Wafflebase reads and writes the file formats your team already uses, so you can bring existing work in and take finished work out. Nothing is locked to the platform.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Product</th><th>Import</th><th>Export</th></tr></thead><tbody><tr><td><strong>Sheets</strong></td><td>Excel (<code>.xlsx</code>)</td><td>— <em>(CSV/JSON via <a href="./../developers/cli.html">CLI</a>)</em></td></tr><tr><td><strong>Docs</strong></td><td>Word (<code>.docx</code>)</td><td>Word (<code>.docx</code>), PDF (<code>.pdf</code>)</td></tr><tr><td><strong>Slides</strong></td><td>PowerPoint (<code>.pptx</code>)</td><td>PowerPoint (<code>.pptx</code>), PDF (<code>.pdf</code>)</td></tr><tr><td><strong>Notes</strong></td><td>—</td><td>—</td></tr><tr><td><strong>PDF</strong></td><td>Upload (<code>.pdf</code>)</td><td>— <em>(view-only)</em></td></tr></tbody></table><p>Import always creates a <strong>new</strong> document; it never overwrites an open one. Export downloads a file from the document you are editing. Notes live entirely inside Wafflebase — they have no file import or export.</p><h2 id="importing-files" tabindex="-1">Importing files <a class="header-anchor" href="#importing-files" aria-label="Permalink to &quot;Importing files&quot;">​</a></h2><p>From your workspace, open the <strong>New</strong> menu and choose an import option:</p><ul><li><strong>Import XLSX</strong> — creates a new spreadsheet from an Excel workbook. Each sheet in the workbook becomes a tab. Values, formulas, and basic cell formatting are brought across.</li><li><strong>Import DOCX</strong> — creates a new document from a Word file, mapping paragraphs, headings, lists, tables, and inline formatting into the editor.</li><li><strong>Import PPTX</strong> — creates a new deck from a PowerPoint file: slides, text boxes, shapes, images, tables, and theme colors are converted to native Wafflebase elements.</li><li><strong>Upload PDF</strong> — stores a PDF as a new document you can read and comment on. Unlike the other imports, the file is kept intact and viewed as-is rather than converted into an editable document. See <a href="./../pdf/viewing-pdfs.html">Viewing PDFs</a>.</li></ul><p>Large files show a progress indicator while they are parsed and any embedded images are uploaded into your workspace.</p><h2 id="exporting-files" tabindex="-1">Exporting files <a class="header-anchor" href="#exporting-files" aria-label="Permalink to &quot;Exporting files&quot;">​</a></h2><h3 id="docs" tabindex="-1">Docs <a class="header-anchor" href="#docs" aria-label="Permalink to &quot;Docs&quot;">​</a></h3><p>In the document editor, open the <strong>Export</strong> menu (the download icon in the header) and choose:</p><ul><li><strong>Word (<code>.docx</code>)</strong> — the full document, including tables and headers/footers.</li><li><strong>PDF (<code>.pdf</code>)</strong> — a paginated, print-ready PDF that mirrors the on-screen page layout.</li></ul><h3 id="slides" tabindex="-1">Slides <a class="header-anchor" href="#slides" aria-label="Permalink to &quot;Slides&quot;">​</a></h3><p>In the presentation editor, open the <strong>Export</strong> menu and choose:</p><ul><li><strong>PowerPoint (<code>.pptx</code>)</strong> — an editable deck with slides, shapes, text, images, tables, and the theme preserved as DrawingML.</li><li><strong>PDF (<code>.pdf</code>)</strong> — one slide per page, ready to share or print.</li></ul><h3 id="sheets" tabindex="-1">Sheets <a class="header-anchor" href="#sheets" aria-label="Permalink to &quot;Sheets&quot;">​</a></h3><p>Spreadsheets export to CSV or JSON through the <a href="./../developers/cli.html">command-line tool</a> (<code>wafflebase sheets …</code>). A built-in download menu in the grid editor is on the roadmap.</p><h2 id="fidelity-notes" tabindex="-1">Fidelity notes <a class="header-anchor" href="#fidelity-notes" aria-label="Permalink to &quot;Fidelity notes&quot;">​</a></h2><p>Wafflebase aims for a faithful round-trip, but the source formats are large and some constructs have no exact equivalent:</p><ul><li><strong>PPTX/DOCX import is best-effort.</strong> Common content — text, lists, tables, shapes, images, and theme colors — converts cleanly. Rare or application-specific features (embedded objects, macros, exotic effects) may be simplified or dropped.</li><li><strong>Fonts</strong> referenced by an imported file must be available in Wafflebase to render identically; otherwise a close fallback is substituted.</li><li><strong>Re-exporting</strong> a file you imported will not be byte-identical to the original, but preserves the structure and content faithfully.</li></ul><h2 id="automating-with-the-cli" tabindex="-1">Automating with the CLI <a class="header-anchor" href="#automating-with-the-cli" aria-label="Permalink to &quot;Automating with the CLI&quot;">​</a></h2><p>Every import/export path above is also scriptable. See the <a href="./../developers/cli.html">CLI reference</a> for <code>docs export</code>, <code>docs import</code>, <code>slides export</code>, <code>slides import</code>, and the <code>sheets</code> cell import/export commands — useful for batch conversions and pipelines.</p>',23)])])}const f=t(i,[["render",s]]);export{m as __pageData,f as default};
